export const BowlGlass: React.FC = () => {
  return (
    <mesh castShadow receiveShadow>
      <sphereGeometry args={[4.2, 64, 64]} />
      <MeshTransmissionMaterial
        backside
        samples={4}
        thickness={0.5}
        chromaticAberration={0.05}
        anisotropy={0.1}
        distortion={0.1}
        distortionScale={0.5}
        temporalDistortion={0.1}
        color="#a5d8ff"
        ior={1.2} // Index of refraction closer to water/glass
        roughness={0.05}
        transmission={0.98}
      />
    </mesh>
  );
};

export const WaterVolume: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (meshRef.current) {
      // Subtle swaying of the water volume itself
      meshRef.current.rotation.z = Math.sin(state.clock.elapsedTime * 0.5) * 0.02;
      meshRef.current.rotation.x = Math.cos(state.clock.elapsedTime * 0.3) * 0.02;
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[4.05, 32, 32]} />
      <meshStandardMaterial
        color="#006699"
        transparent
        opacity={0.15}
        roughness={0}
        metalness={0.1}
        side={THREE.DoubleSide}
      />
    </mesh>
  );
};

