import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Instance, Instances } from '@react-three/drei';
import * as THREE from 'three';

interface SmokeParticleProps {
  random: number;
}

const SmokeParticle: React.FC<SmokeParticleProps> = ({ random }) => {
  const ref = useRef<any>(null);
  const speed = 0.5 + Math.random() * 0.5;
  const offset = Math.random() * Math.PI * 2;

  useFrame((state, delta) => {
    if (!ref.current) return;

    // Move up
    ref.current.position.y += speed * delta;
    // Drift
    ref.current.position.x += Math.sin(state.clock.elapsedTime + offset) * 0.2 * delta;

    // Fade out and scale up logic would ideally go here via shader, 
    // but for simple instances we reset position for loop
    if (ref.current.position.y > 3) {
      ref.current.position.y = 0;
      ref.current.position.x = 0;
      ref.current.position.z = 0;
      ref.current.scale.setScalar(0.2);
    } else {
        const s = ref.current.scale.x + delta * 0.5;
        ref.current.scale.setScalar(s);
    }
  });

  return <Instance ref={ref} color="white" scale={0.2} position={[0, 0, 0]} />;
};

