export const Fish: React.FC<FishCharacterProps> = ({ status }) => {
  const groupRef = useRef<THREE.Group>(null);

  // Random swimming parameters
  const swimParams = useMemo(() => ({
    speed: 1,
    radius: 1.5 + Math.random(),
    yOffset: Math.random() * 0.5,
    randomPhase: Math.random() * Math.PI
  }), []);

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    if (status === BotStatus.DISCONNECTED) {
      // Dead fish logic: Float up and turn belly up
      groupRef.current.position.y = THREE.MathUtils.lerp(groupRef.current.position.y, 3.5, delta * 0.5);
      // Rotate belly up (Z rotation PI)
      groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, Math.PI, delta * 1);
      // Gentle bobbing while dead
      groupRef.current.rotation.x = Math.sin(state.clock.elapsedTime) * 0.05;
      return;
    }

    // Reset rotation from dead state
    if (groupRef.current.rotation.z > 0.1) {
       groupRef.current.rotation.z = THREE.MathUtils.lerp(groupRef.current.rotation.z, 0, delta * 2);
    }

    // Swimming Logic
    const t = state.clock.elapsedTime * swimParams.speed + swimParams.randomPhase;

    // Smooth idle swimming
    const x = Math.sin(t) * swimParams.radius;
    const z = Math.cos(t * 0.8) * (swimParams.radius * 0.6);
    const y = Math.sin(t * 0.5) * 0.5;

    // Target position vector
    const targetPos = new THREE.Vector3(x, y, z);

    // Smoothly move current position to target
    groupRef.current.position.lerp(targetPos, delta * 2);

    // Look ahead calculation
    const lookAtPos = new THREE.Vector3(
        Math.sin(t + 0.1) * swimParams.radius,
        Math.sin((t + 0.1) * 0.5) * 0.5,
        Math.cos((t + 0.1) * 0.8) * (swimParams.radius * 0.6)
    );
    groupRef.current.lookAt(lookAtPos);

    // Add subtle banking when turning
    const bank = (x - lookAtPos.x) * 0.2;
    groupRef.current.rotation.z += bank;
  });

  // Rotate entire fish to be horizontal by default (Capsule is vertical by default)
  // We apply this inside the procedural body or transform the group. 
  // Here we adjust the inner content rotation.

  return (
    <group ref={groupRef}>
      <group rotation={[0, -Math.PI / 2, Math.PI / 2]}> 
        <ProceduralFishBody />
        <Tail speed={status === BotStatus.WORKING ? 2 : 1} />
        {status === BotStatus.WORKING && <Cigarette />}
      </group>
    </group>
  );
};

