const Tail: React.FC<{ speed: number }> = ({ speed }) => {
  const ref = useRef<THREE.Group>(null);
  useFrame((state) => {
    if (ref.current) {
        // Faster, snappier tail movement
        ref.current.rotation.y = Math.sin(state.clock.elapsedTime * speed * 8) * 0.4;
    }
  });

  return (
    <group ref={ref} position={[-1.1, 0, 0]}>
        <mesh rotation={[0, 0, Math.PI / 2]} scale={[1, 1, 0.1]}>
            <coneGeometry args={[0.6, 1.2, 32]} />
